3. import React, { useMemo, useState } from 'react';
4. import { View, Text, TextInput, SectionList, StyleSheet, SectionListData } from 'react-native';
5. import { Meta, StoryObj } from '@storybook/react';
6. import * as AllIcons from './assets';
7. import * as MultiColorIcons from './assets-multi';
8. 
9. type IconEntry = {
10. 	name: string;
11. 	displayName: string;
12. 	multiColor: boolean;
13. 	Component: React.ComponentType<{ width?: number; height?: number; color?: string }>;
14. };
15. 
16. type IconRow = IconEntry[];
17. type RowSection = SectionListData<IconRow, { title: string; count: number }>;
18. 
19. function pascalToKebab(name: string): string {
20. 	return name
21. 		.replace(/([a-z0-9])([A-Z])/g, '$1-$2')
22. 		.replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
23. 		.toLowerCase();
24. }
25. 
26. function getCategory(kebabName: string): string {
27. 	const first = kebabName.split('-')[0];
28. 	return first.charAt(0).toUpperCase() + first.slice(1);
29. }
30. 
31. const multiColorNames = new Set(Object.keys(MultiColorIcons));
32. 
33. const allIcons: IconEntry[] = Object.entries(AllIcons)
34. 	.filter(([name]) => !/\d+$/.test(name))
35. 	.map(([name, Component]) => ({
36. 		name,
37. 		displayName: pascalToKebab(name),
38. 		multiColor: multiColorNames.has(name),
39. 		Component: Component as IconEntry['Component']
40. 	}))
41. 	.sort((a, b) => a.displayName.localeCompare(b.displayName));
42. 
43. const COLUMN_COUNT = 4;
44. 
45. function chunk(arr: IconEntry[], size: number): IconRow[] {
46. 	const rows: IconRow[] = [];
47. 	for (let i = 0; i < arr.length; i += size) {
48. 		rows.push(arr.slice(i, i + size));
49. 	}
50. 	return rows;
51. }
52. 
53. function buildSections(icons: IconEntry[]): { sections: RowSection[]; total: number } {
54. 	const grouped = new Map<string, IconEntry[]>();
55. 	for (const icon of icons) {
56. 		const category = getCategory(icon.displayName);
57. 		const list = grouped.get(category);
58. 		if (list) {
59. 			list.push(icon);
60. 		} else {
61. 			grouped.set(category, [icon]);
62. 		}
63. 	}
64. 
65. 	const sections = Array.from(grouped.entries())
66. 		.sort(([a], [b]) => a.localeCompare(b))
67. 		.map(([title, items]) => ({
68. 			title,
69. 			count: items.length,
70. 			data: chunk(items, COLUMN_COUNT)
71. 		}));
72. 
73. 	return { sections, total: icons.length };
74. }
75. 
76. const IconGallery = () => {
77. 	const [search, setSearch] = useState('');
78. 
79. 	const { sections, matchCount } = useMemo(() => {
80. 		const query = search.toLowerCase().trim();
81. 		const filtered = query
82. 			? allIcons.filter(
83. 					(icon) => icon.displayName.includes(query) || icon.name.toLowerCase().includes(query)
84. 				)
85. 			: allIcons;
86. 
87. 		const { sections: s, total } = buildSections(filtered);
88. 		return { sections: s, matchCount: total };
89. 	}, [search]);
90. 
91. 	const isSearching = search.trim().length > 0;
92. 
93. 	return (
94. 		<View style={styles.container}>
95. 			<View style={styles.header}>
96. 				<Text style={styles.title}>Icon Gallery</Text>
97. 				<Text style={styles.countText}>
98. 					{isSearching ? `${matchCount} of ${allIcons.length} icons` : `${allIcons.length} icons`}
99. 				</Text>
100. 				<TextInput
101. 					style={styles.searchInput}
102. 					placeholder="Search icons..."
103. 					placeholderTextColor="#999"
104. 					value={search}
105. 					onChangeText={setSearch}
106. 					autoCapitalize="none"
107. 					autoCorrect={false}
108. 				/>
109. 			</View>
110. 			<SectionList<IconRow, { title: string; count: number }>
111. 				sections={sections}
112. 				keyExtractor={(row) => row.map((i) => i.name).join(',')}
113. 				stickySectionHeadersEnabled
114. 				renderSectionHeader={({ section }) => (
115. 					<View style={styles.sectionHeader}>
116. 						<Text style={styles.sectionTitle}>{section.title}</Text>
117. 						<Text style={styles.sectionCount}>{section.count}</Text>
118. 					</View>
119. 				)}
120. 				renderItem={({ item: rowItems }) => (
121. 					<View style={styles.row}>
122. 						{rowItems.map((icon) => (
123. 							<View
124. 								key={icon.name}
125. 								style={styles.iconBox}>
126. 								{icon.multiColor ? (
127. 									<icon.Component
128. 										width={72}
129. 										height={24}
130. 									/>
131. 								) : (
132. 									<icon.Component
133. 										width={24}
134. 										height={24}
135. 										color="#000"
136. 									/>
137. 								)}
138. 								<Text
139. 									style={styles.label}
140. 									numberOfLines={2}>
141. 									{icon.displayName}
142. 								</Text>
143. 							</View>
144. 						))}
145. 						{rowItems.length < COLUMN_COUNT &&
146. 							Array.from(
147. 								{ length: COLUMN_COUNT - rowItems.length },
148. 								(_, col) => rowItems.length + col
149. 							).map((colPosition) => (
150. 								<View
151. 									key={`spacer-col${colPosition}`}
152. 									style={styles.iconBox}
153. 								/>
154. 							))}
155. 					</View>
156. 				)}
157. 				ListEmptyComponent={
158. 					<View style={styles.emptyContainer}>
159. 						<Text style={styles.emptyText}>No icons match "{search}"</Text>
160. 					</View>
161. 				}
162. 			/>
163. 		</View>
164. 	);
165. };
166. 
167. const meta = {
168. 	title: 'Icon Library/Icons',
169. 	component: IconGallery
170. } satisfies Meta<typeof IconGallery>;
171. 
172. export default meta;
173. type Story = StoryObj<typeof meta>;
174. 
