 /** @format */

 import React, { useMemo, useState } from 'react';
 import { View, Text, TextInput, SectionList, StyleSheet, SectionListData } from 'react-native';
 import { Meta, StoryObj } from '@storybook/react';
 import * as AllIcons from './assets';
 import * as MultiColorIcons from './assets-multi';

 type IconEntry = {
 	name: string;
 	displayName: string;
 	multiColor: boolean;
 	Component: React.ComponentType<{ width?: number; height?: number; color?: string }>;
 };

 type IconRow = IconEntry[];
 type RowSection = SectionListData<IconRow, { title: string; count: number }>;

 function pascalToKebab(name: string): string {
 	return name
 		.replace(/([a-z0-9])([A-Z])/g, '$1-$2')
 		.replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
 		.toLowerCase();
 }

 function getCategory(kebabName: string): string {
 	const first = kebabName.split('-')[0];
 	return first.charAt(0).toUpperCase() + first.slice(1);
 }

 const multiColorNames = new Set(Object.keys(MultiColorIcons));

 const allIcons: IconEntry[] = Object.entries(AllIcons)
 	.filter(([name]) => !/\d+$/.test(name))
 	.map(([name, Component]) => ({
 		name,
 		displayName: pascalToKebab(name),
 		multiColor: multiColorNames.has(name),
 		Component: Component as IconEntry['Component']
 	}))
 	.sort((a, b) => a.displayName.localeCompare(b.displayName));

 const COLUMN_COUNT = 4;

 function chunk(arr: IconEntry[], size: number): IconRow[] {
 	const rows: IconRow[] = [];
 	for (let i = 0; i < arr.length; i += size) {
 		rows.push(arr.slice(i, i + size));
 	}
 	return rows;
 }

 function buildSections(icons: IconEntry[]): { sections: RowSection[]; total: number } {
 	const grouped = new Map<string, IconEntry[]>();
 	for (const icon of icons) {
 		const category = getCategory(icon.displayName);
 		const list = grouped.get(category);
 		if (list) {
 			list.push(icon);
 		} else {
 			grouped.set(category, [icon]);
 		}
 	}

 	const sections = Array.from(grouped.entries())
 		.sort(([a], [b]) => a.localeCompare(b))
 		.map(([title, items]) => ({
 			title,
 			count: items.length,
 			data: chunk(items, COLUMN_COUNT)
 		}));

 	return { sections, total: icons.length };
 }

 const IconGallery = () => {
 	const [search, setSearch] = useState('');

 	const { sections, matchCount } = useMemo(() => {
 		const query = search.toLowerCase().trim();
 		const filtered = query
 			? allIcons.filter(
 					(icon) => icon.displayName.includes(query) || icon.name.toLowerCase().includes(query)
 				)
 			: allIcons;

 		const { sections: s, total } = buildSections(filtered);
 		return { sections: s, matchCount: total };
 	}, [search]);

 	const isSearching = search.trim().length > 0;

 	return (
 		<View style={styles.container}>
 			<View style={styles.header}>
 				<Text style={styles.title}>Icon Gallery</Text>
 				<Text style={styles.countText}>
 					{isSearching ? `${matchCount} of ${allIcons.length} icons` : `${allIcons.length} icons`}
 				</Text>
 				<TextInput
 					style={styles.searchInput}
 					placeholder="Search icons..."
 					placeholderTextColor="#999"
 					value={search}
 					onChangeText={setSearch}
 					autoCapitalize="none"
 					autoCorrect={false}
 				/>
 			</View>
 			<SectionList<IconRow, { title: string; count: number }>
 				sections={sections}
 				keyExtractor={(row) => row.map((i) => i.name).join(',')}
 				stickySectionHeadersEnabled
 				renderSectionHeader={({ section }) => (
 					<View style={styles.sectionHeader}>
 						<Text style={styles.sectionTitle}>{section.title}</Text>
 						<Text style={styles.sectionCount}>{section.count}</Text>
 					</View>
 				)}
 				renderItem={({ item: rowItems }) => (
 					<View style={styles.row}>
 						{rowItems.map((icon) => (
 							<View
 								key={icon.name}
 								style={styles.iconBox}>
 								{icon.multiColor ? (
 									<icon.Component
 										width={72}
 										height={24}
 									/>
 								) : (
 									<icon.Component
 										width={24}
 										height={24}
 										color="#000"
 									/>
 								)}
 								<Text
 									style={styles.label}
 									numberOfLines={2}>
 									{icon.displayName}
 								</Text>
 							</View>
 						))}
 						{rowItems.length < COLUMN_COUNT &&
 							Array.from(
 								{ length: COLUMN_COUNT - rowItems.length },
 								(_, col) => rowItems.length + col
 							).map((colPosition) => (
 								<View
 									key={`spacer-col${colPosition}`}
 									style={styles.iconBox}
 								/>
 							))}
 					</View>
 				)}
 				ListEmptyComponent={
 					<View style={styles.emptyContainer}>
 						<Text style={styles.emptyText}>No icons match "{search}"</Text>
 					</View>
 				}
 			/>
 		</View>
 	);
 };

 const meta = {
 	title: 'Icon Library/Icons',
 	component: IconGallery
 } satisfies Meta<typeof IconGallery>;

 export default meta;
 type Story = StoryObj<typeof meta>;

 export const Overview: Story = {};

