1. #!/usr/bin/env node
2. 
3. /**
4.  * @format
5.  *
6.  * Single-pass React Native icon generation script.
7.  *
8.  * Reads source SVGs, runs them through SVGR with SVGO optimization,
9.  * and writes final components with the shared IconProps interface.
10.  * No post-processing step needed.
11.  *
12.  * Usage: node tools/scripts/generate-rn-icons.js
13.  */
14. 
15. const fs = require('fs');
16. const path = require('path');
17. const { transform } = require('@svgr/core');
18. const { singleColorConfig, multiColorConfig } = require('../svg-conversion-configs/svgr.react-native.config');
19. 
20. const ICONS_SRC = path.resolve(__dirname, '../../libs/icons');
21. const ICON_LIB = path.resolve(
22. 	__dirname,
23. 	'../../libs/output/hmf-react-native-icons/src/lib/components/icon-library'
24. );
25. const ASSETS_DIR = path.join(ICON_LIB, 'assets');
26. const MULTI_DIR = path.join(ICON_LIB, 'assets-multi');
27. 
28. const VALID_SIZES = [12, 16, 20, 24, 32, 40, 48];
29. 
30. // ---------------------------------------------------------------------------
31. // Helpers
32. // ---------------------------------------------------------------------------
33. 
34. function kebabToPascal(str) {
35. 	return str
36. 		.split('-')
37. 		.map((part) => part.charAt(0).toUpperCase() + part.slice(1))
38. 		.join('');
39. }
40. 
41. function ensureDir(dir) {
42. 	if (!fs.existsSync(dir)) {
43. 		fs.mkdirSync(dir, { recursive: true });
44. 	}
45. }
46. 
47. function cleanDir(dir) {
48. 	if (!fs.existsSync(dir)) return;
49. 	for (const file of fs.readdirSync(dir)) {
50. 		const full = path.join(dir, file);
51. 		if (fs.statSync(full).isFile()) {
52. 			fs.unlinkSync(full);
53. 		}
54. 	}
55. }
56. 
57. function collectSvgFiles(baseDir) {
58. 	const entries = fs.readdirSync(baseDir, { withFileTypes: true });
59. 	const files = [];
60. 
61. 	for (const entry of entries) {
62. 		const fullPath = path.join(baseDir, entry.name);
63. 		if (entry.isFile() && entry.name.endsWith('.svg')) {
64. 			files.push(fullPath);
65. 		} else if (entry.isDirectory()) {
66. 			// Size variant directories (e.g., alert-help-filled/)
67. 			const subFiles = fs.readdirSync(fullPath).filter((f) => f.endsWith('.svg'));
68. 			for (const sub of subFiles) {
69. 				files.push(path.join(fullPath, sub));
70. 			}
71. 		}
72. 	}
73. 
74. 	return files;
75. }
76. 
77. /**
78.  * Parse an SVG filename into base name and optional size.
79.  * e.g. "alert-help-filled-12.svg" -> { baseName: "alert-help-filled", size: 12 }
80.  *      "alert-help-filled.svg"    -> { baseName: "alert-help-filled", size: null }
81.  */
82. function parseSvgFilename(filePath) {
83. 	const name = path.basename(filePath, '.svg');
84. 	const sizeMatch = name.match(/^(.+)-(\d+)$/);
85. 
86. 	if (sizeMatch) {
87. 		const size = parseInt(sizeMatch[2], 10);
88. 		if (VALID_SIZES.includes(size)) {
89. 			return { baseName: sizeMatch[1], size };
90. 		}
91. 	}
92. 
93. 	return { baseName: name, size: null };
94. }
95. 
96. // ---------------------------------------------------------------------------
97. // SVGR transform
98. // ---------------------------------------------------------------------------
99. 
100. async function transformSvg(svgCode, componentName, config) {
101. 	const code = await transform(svgCode, {
102. 		native: true,
103. 		typescript: true,
104. 		plugins: ['@svgr/plugin-svgo', '@svgr/plugin-jsx'],
105. 		svgoConfig: config.svgoConfig,
106. 		template: config.template,
107. 		prettier: false,
108. 	}, {
109. 		componentName: `Svg${componentName}`,
110. 	});
111. 
112. 	return code;
113. }
114. 
115. // ---------------------------------------------------------------------------
116. // Main generation
117. // ---------------------------------------------------------------------------
118. 
119. async function generateIcons(srcDir, outDir, svgrConfig) {
120. 	const svgFiles = collectSvgFiles(srcDir);
121. 	const generated = [];
122. 	const seenNames = new Set();
123. 	for (const svgPath of svgFiles) {
124. 		const svgCode = fs.readFileSync(svgPath, 'utf8');
125. 		const { baseName, size } = parseSvgFilename(svgPath);
126. 
127. 		const pascalBase = kebabToPascal(baseName);
128. 		const componentName = size ? `${pascalBase}${size}` : pascalBase;
129. 		const nameLower = componentName.toLowerCase();
130. 		const outFile = path.join(outDir, `${componentName}.tsx`);
131. 
132. 		if (seenNames.has(nameLower) || fs.existsSync(outFile)) {
133. 			console.warn(`  SKIP: ${path.basename(svgPath)} — ${componentName} collides with existing component`);
134. 			continue;
135. 		}
136. 		seenNames.add(nameLower);
137. 
138. 		const code = await transformSvg(svgCode, componentName, svgrConfig);
139. 
140. 		fs.writeFileSync(outFile, code);
141. 		generated.push({ componentName, baseName: pascalBase, size });
142. 	}
143. 
144. 	return generated;
145. }
146. 
147. function writeIndex(outDir, entries, multiEntries) {
148. 	const lines = [];
149. 
150. 	// Single-color
151. 	for (const { componentName } of entries) {
152. 		lines.push(`export { default as ${componentName} } from './${componentName}';`);
153. 	}
154. 
155. 	// Multi-color (from sibling directory)
156. 	if (multiEntries) {
157. 		for (const { componentName } of multiEntries) {
158. 			lines.push(`export { default as ${componentName} } from '../assets-multi/${componentName}';`);
159. 		}
160. 	}
161. 
162. 	lines.sort();
163. 	fs.writeFileSync(path.join(outDir, 'index.ts'), lines.join('\n') + '\n');
164. }
165. 
166. async function main() {
167. 	console.log('Generating React Native icons...');
168. 
169. 	// Clean output dirs
170. 	ensureDir(ASSETS_DIR);
171. 	ensureDir(MULTI_DIR);
172. 	cleanDir(ASSETS_DIR);
173. 	cleanDir(MULTI_DIR);
174. 
175. 	// Generate single-color icons
176. 	const singleEntries = await generateIcons(
177. 		path.join(ICONS_SRC, 'single-color'),
178. 		ASSETS_DIR,
179. 		singleColorConfig
180. 	);
181. 	console.log(`  Single-color: ${singleEntries.length} components`);
182. 
183. 	// Generate multi-color icons
184. 	const multiEntries = await generateIcons(
185. 		path.join(ICONS_SRC, 'multi-color'),
186. 		MULTI_DIR,
187. 		multiColorConfig
188. 	);
189. 	console.log(`  Multi-color: ${multiEntries.length} components`);
190. 
191. 	// Write index files
192. 	writeIndex(ASSETS_DIR, singleEntries, multiEntries);
193. 	writeIndex(MULTI_DIR, multiEntries, null);
194. 
195. 	// Summary
196. 	const withVariants = new Set(
197. 		singleEntries.filter((e) => e.size !== null).map((e) => e.baseName)
198. 	);
199. 	console.log(`  Size variants: ${withVariants.size} icons have per-size SVGs`);
200. 	console.log(`  Total: ${singleEntries.length + multiEntries.length} components`);
201. 	console.log('Done.');
202. }
203. 
204. main().catch((err) => {
205. 	console.error('Error generating icons:', err);
206. 	process.exit(1);
207. });
208.

