 /** @format */

 import { IconRegistry, getIconRegistry } from './icon-registry';

 describe('IconRegistry', () => {
 	let registry: IconRegistry;

 	beforeEach(() => {
 		registry = new IconRegistry();
 	});

 	afterEach(() => {
 		registry.clear();
 	});

 	describe('registerIcons', () => {
 		it('should register icons', () => {
 			registry.registerIcons([
 				{
 					name: 'test-icon',
 					data: '<svg><path d="M0 0"/></svg>'
 				}
 			]);

 			expect(registry.hasIcon('test-icon')).toBe(true);
 			expect(registry.size).toBe(1);
 		});

 		it('should register multiple icons', () => {
 			registry.registerIcons([
 				{ name: 'icon-1', data: '<svg>1</svg>' },
 				{ name: 'icon-2', data: '<svg>2</svg>' },
 				{ name: 'icon-3', data: '<svg>3</svg>' }
 			]);

 			expect(registry.size).toBe(3);
 			expect(registry.getRegisteredNames()).toEqual(['icon-1', 'icon-2', 'icon-3']);
 		});

 		it('should register icons with size variants', () => {
 			registry.registerIcons([
 				{
 					name: 'test-icon',
 					data: '<svg>24</svg>',
 					sizes: {
 						16: '<svg>16</svg>',
 						32: '<svg>32</svg>'
 					}
 				}
 			]);

 			expect(registry.hasIcon('test-icon')).toBe(true);
 		});
 	});

 	describe('getIconBySize', () => {
 		beforeEach(() => {
 			registry.registerIcons([
 				{
 					name: 'test-icon',
 					data: '<svg>24</svg>',
 					sizes: {
 						16: '<svg>16</svg>',
 						32: '<svg>32</svg>'
 					}
 				}
 			]);
 		});

 		it('should return base icon when no size is specified', () => {
 			const svg = registry.getIconBySize('test-icon');
 			expect(svg).toBe('<svg>24</svg>');
 		});

 		it('should return sized variant when available', () => {
 			const svg16 = registry.getIconBySize('test-icon', 16);
 			expect(svg16).toBe('<svg>16</svg>');

 			const svg32 = registry.getIconBySize('test-icon', 32);
 			expect(svg32).toBe('<svg>32</svg>');
 		});

 		it('should fall back to base icon when size variant not available', () => {
 			const svg = registry.getIconBySize('test-icon', 48);
 			expect(svg).toBe('<svg>24</svg>');
 		});

 		it('should return undefined for unregistered icon', () => {
 			const svg = registry.getIconBySize('unknown-icon');
 			expect(svg).toBeUndefined();
 		});
 	});

 	describe('hasIcon', () => {
 		it('should return true for registered icon', () => {
 			registry.registerIcons([{ name: 'test-icon', data: '<svg></svg>' }]);
 			expect(registry.hasIcon('test-icon')).toBe(true);
 		});

 		it('should return false for unregistered icon', () => {
 			expect(registry.hasIcon('unknown-icon')).toBe(false);
 		});
 	});

 	describe('getRegisteredNames', () => {
 		it('should return empty array when no icons registered', () => {
 			expect(registry.getRegisteredNames()).toEqual([]);
 		});

 		it('should return all registered icon names', () => {
 			registry.registerIcons([
 				{ name: 'icon-a', data: '<svg>a</svg>' },
 				{ name: 'icon-b', data: '<svg>b</svg>' },
 				{ name: 'icon-c', data: '<svg>c</svg>' }
 			]);

 			const names = registry.getRegisteredNames();
 			expect(names).toHaveLength(3);
 			expect(names).toContain('icon-a');
 			expect(names).toContain('icon-b');
 			expect(names).toContain('icon-c');
 		});
 	});

 	describe('clear', () => {
 		it('should remove all icons', () => {
 			registry.registerIcons([
 				{ name: 'icon-1', data: '<svg>1</svg>' },
 				{ name: 'icon-2', data: '<svg>2</svg>' }
 			]);

 			expect(registry.size).toBe(2);

 			registry.clear();

 			expect(registry.size).toBe(0);
 			expect(registry.hasIcon('icon-1')).toBe(false);
 			expect(registry.hasIcon('icon-2')).toBe(false);
 		});
 	});

 	describe('size property', () => {
 		it('should return 0 when no icons registered', () => {
 			expect(registry.size).toBe(0);
 		});

 		it('should return correct count of registered icons', () => {
 			registry.registerIcons([
 				{ name: 'icon-1', data: '<svg>1</svg>' },
 				{ name: 'icon-2', data: '<svg>2</svg>' }
 			]);

 			expect(registry.size).toBe(2);
 		});
 	});
 });

 describe('getIconRegistry', () => {
 	it('should return singleton instance', () => {
 		const registry1 = getIconRegistry();
 		const registry2 = getIconRegistry();

 		expect(registry1).toBe(registry2);
 	});

 	it('should persist registrations across calls', () => {
 		const registry1 = getIconRegistry();
 		registry1.registerIcons([{ name: 'test-icon', data: '<svg></svg>' }]);

 		const registry2 = getIconRegistry();
 		expect(registry2.hasIcon('test-icon')).toBe(true);
 	});
 });

