 /** @format */

 /**
  * Internal registry entry structure
  */
 interface IconEntry<C> {
 	base: C;
 	sizes?: Partial<Record<number, C>>;
 }

 /**
  * Registration tuple format:
  * - [name, baseComponent] - Icon with no size variants
  * - [name, baseComponent, sizeMap] - Icon with size variants
  */
 export type IconRegistration<C> = [string, C] | [string, C, Partial<Record<number, C>>];

 /**
  * Icon Registry Service
  *
  * Manages registered icons and provides size-based resolution.
  * Mirrors the Angular HomefieldIconsLibraryService pattern.
  */
 export class IconRegistryService<C> {
 	readonly registry = new Map<string, IconEntry<C>>();

 	/**
 	 * Register icons for use with an Icon component.
 	 *
 	 * @param icons - Array of icon registrations
 	 */
 	registerIcons(icons: IconRegistration<C>[]): void {
 		icons.forEach(([name, component, sizes]) => {
 			this.registry.set(name, { base: component, sizes });
 		});
 	}

 	/**
 	 * Get icon component by name and optional size.
 	 * 1. If size is provided and a sized variant exists, return it
 	 * 2. Otherwise, fall back to the base icon
 	 *
 	 * @param name - Icon name in kebab-case (e.g., 'alert-help-filled')
 	 * @param size - Optional numeric size (e.g., 32)
 	 * @returns The icon component or undefined if not registered
 	 */
 	getIconBySize(name: string, size?: number): C | undefined {
 		const entry = this.registry.get(name);
 		if (!entry) {
 			return undefined;
 		}

 		if (size && entry.sizes?.[size]) {
 			return entry.sizes[size];
 		}

 		return entry.base;
 	}

 	/**
 	 * Check if an icon is registered
 	 */
 	hasIcon(name: string): boolean {
 		return this.registry.has(name);
 	}

 	/**
 	 * Get all registered icon names
 	 */
 	getRegisteredNames(): string[] {
 		return Array.from(this.registry.keys());
 	}

 	/**
 	 * Clear all registered icons (useful for testing)
 	 */
 	clear(): void {
 		this.registry.clear();
 	}
 }

