 		iconMap.set(baseName, { sizes: [] });
 	}
 	iconMap.get(baseName).sizes.push(size);
 }

 /**
  * Process sized icon and update map
  * @param {string} baseName - Base icon name without size
  * @param {number} size - Icon size
  * @param {string} fullName - Full icon name with size
  * @param {Map} iconMap - Icon map to update
  */
 function processSizedIcon(baseName, size, fullName, iconMap) {
 	if (VALID_SIZES.includes(size)) {
 		addIconSize(iconMap, baseName, size);
 	} else {
 		addIconIfNotExists(iconMap, fullName);
 	}
 }

 /**
  * Process icon name and update map
  * @param {string} fullName - Full icon name
  * @param {Map} iconMap - Icon map to update
  */
 function processIconName(fullName, iconMap) {
 	const sizeMatch = fullName.match(/^(.+)-(\d+)$/);

 	if (sizeMatch) {
 		const baseName = sizeMatch[1];
 		const size = parseInt(sizeMatch[2], 10);
 		processSizedIcon(baseName, size, fullName, iconMap);
 	} else {
 		addIconIfNotExists(iconMap, fullName);
 	}
 }

 /**
  * Sort sizes for all icons in the map
  * @param {Map} iconMap - Icon map to sort
  */
 function sortIconSizes(iconMap) {
 	for (const [, info] of iconMap) {
 		info.sizes.sort((a, b) => a - b);
 	}
 }

 /**
  * Parse icon files to extract base names and identify size variants
  * @param {string} dir - Directory to scan
  * @returns {Map<string, { sizes: number[] }>} Map of base icon names to their available sizes
  */
 function parseIconFiles(dir) {
 	if (!fs.existsSync(dir)) {
 		console.warn(`Warning: Directory not found: ${dir}`);
 		return new Map();
 	}

 	const files = fs.readdirSync(dir).filter((f) => f.endsWith('.icon.ts'));
 	const iconMap = new Map();

 	files.forEach((file) => {
 		const iconName = extractIconName(file);
 		if (iconName) {
 			processIconName(iconName, iconMap);
 		}
 	});

 	sortIconSizes(iconMap);
 	return iconMap;
 }

 /**
  * Extract export names from a barrel file
  * @param {string} barrelFile - Path to index.ts barrel file
  * @returns {string[]} Array of export names
  */
 function extractExportNames(barrelFile) {
 	if (!fs.existsSync(barrelFile)) {
 		return [];
 	}

 	const content = fs.readFileSync(barrelFile, 'utf-8');
 	const exportRegex = /export const (\w+):/g;
 	const exports = [];
 	let match;

 	while ((match = exportRegex.exec(content)) !== null) {
 		exports.push(match[1]);
 	}

 	return exports;
 }

 /**
  * Generate the icon names TypeScript file
  */
 function generateIconNamesFile(singleColorIcons, multiColorIcons) {
 	console.log('Generating icon names file...');

 	// Combine all icon names
 	const allIconNames = [...singleColorIcons.keys(), ...multiColorIcons.keys()].sort();

 	// Count icons with size variants
 	let iconsWithVariants = 0;
 	for (const [, info] of singleColorIcons) {
 		if (info.sizes.length > 0) {
 			iconsWithVariants++;
 		}
 	}
 	for (const [, info] of multiColorIcons) {
 		if (info.sizes.length > 0) {
 			iconsWithVariants++;
 		}
 	}

 	// Generate file content
 	const lines = [
 		'/* eslint-disable */',
 		'/** @format */',
 		'',
 		'/**',
 		' * This file was auto-generated by generate-web-components-icon-helpers.js',
 		' * Do not edit manually - regenerate with: npm run generate-icons',
 		' */',
 		'',
 		'/**',
 		' * All available icon names in kebab-case',
 		' */',
 		'export const ALL_ICON_NAMES = [',
 		...allIconNames.map((name) => `\t'${name}',`),
 		'] as const;',
 		'',
 		'/**',
 		' * Type union of all valid icon names',
 		' */',
 		'export type HomefieldIconName = (typeof ALL_ICON_NAMES)[number];',
 		'',
 		'/**',
 		' * Map of icon names to their available size variants',
 		' * Icons not in this map only have the default 24px size',
 		' */',
 		'export const ICON_SIZE_VARIANTS: Partial<Record<HomefieldIconName, number[]>> = {'
 	];

 	// Add size variants for icons that have them
 	for (const [name, info] of singleColorIcons) {
 		if (info.sizes.length > 0) {
 			lines.push(`\t'${name}': [${info.sizes.join(', ')}],`);
 		}
 	}
 	for (const [name, info] of multiColorIcons) {
 		if (info.sizes.length > 0) {
 			lines.push(`\t'${name}': [${info.sizes.join(', ')}],`);
 		}
 	}

 	lines.push('};');
 	lines.push('');

 	// Write file
 	fs.writeFileSync(ICON_NAMES_OUTPUT, lines.join('\n'));
 	console.log(`Generated: ${ICON_NAMES_OUTPUT}`);
 	console.log(`  - Total unique icon names: ${allIconNames.length}`);
 	console.log(`  - Icons with size variants: ${iconsWithVariants}`);
 }

 /**
  * Generate the register-all.ts convenience file
  */
 function generateRegisterAllFile() {
 	console.log('Generating register-all.ts file...');

 	// Extract actual export names from generated barrel files
 	const singleColorExports = [];
 	const singleColorDir = path.join(ICONS_DIR);
 	if (fs.existsSync(singleColorDir)) {
 		const files = fs.readdirSync(singleColorDir).filter(f => f.endsWith('.icon.ts'));
 		files.forEach(file => {
 			const content = fs.readFileSync(path.join(singleColorDir, file), 'utf-8');
 			const match = content.match(/export const (\w+):/);
 			if (match) {
 				singleColorExports.push(match[1]);
 			}
 		});
 	}

 	const multiColorExports = [];
 	const multiColorDir = path.join(MULTI_ICONS_DIR);
 	if (fs.existsSync(multiColorDir)) {
 		const files = fs.readdirSync(multiColorDir).filter(f => f.endsWith('.icon.ts'));
 		files.forEach(file => {
 			const content = fs.readFileSync(path.join(multiColorDir, file), 'utf-8');
 			const match = content.match(/export const (\w+):/);
 			if (match) {
 				multiColorExports.push(match[1]);
 			}
 		});
 	}

 	const lines = [
 		'/* eslint-disable */',
 		'/** @format */',
 		'',
 		'/**',
