 	lines.push(' * ');
 	lines.push(' * registerAllIcons();');
 	lines.push(' * ```');
 	lines.push(' */');
 	lines.push('export function registerAllIcons(): void {');
 	lines.push('\tregisterIcons([');

 	// Add all icons to the array
 	const allIcons = [...singleColorExports, ...multiColorExports].map(name => `\t\t${name}`);

 	lines.push(allIcons.join(',\n'));
 	lines.push('\t]);');
 	lines.push('}');
 	lines.push('');

 	// Write file
 	fs.writeFileSync(REGISTER_ALL_OUTPUT, lines.join('\n'));
 	console.log(`Generated: ${REGISTER_ALL_OUTPUT}`);
 	console.log(`  - Total icons registered: ${allIcons.length}`);
 }

 /**
  * Main execution
  */
 function main() {
 	console.log('=== Generating Web Components Icon Helpers ===\n');

 	// Parse single-color icons
 	const singleColorIcons = parseIconFiles(ICONS_DIR);
 	console.log(`Found ${singleColorIcons.size} single-color base icons`);

 	// Parse multi-color icons
 	const multiColorIcons = parseIconFiles(MULTI_ICONS_DIR);
 	console.log(`Found ${multiColorIcons.size} multi-color icons\n`);

 	// Generate files
 	generateIconNamesFile(singleColorIcons, multiColorIcons);
 	generateRegisterAllFile();

 	console.log('\n✅ Done!');
 }

 // Run
 try {
 	main();
 } catch (error) {

