 /** @format */

 import React, { CSSProperties } from 'react';
 import { ICON_SIZE_ALIASES, IconSizeType } from './icon-size-aliases';
 import { iconRegistry, registerIcons, IconComponent, IconRegistration } from './IconRegistry';

 /**
  * Props for the HomefieldIcon component
  */
 export interface HomefieldIconProps {
 	/** Icon name in kebab-case (e.g., 'alert-help-filled') */
 	name: string;
 	/** Size alias (e.g., 'md', 'lg') or specific pixel value (e.g., 32) */
 	size?: (typeof IconSizeType)[number] | number;
 	/** CSS color value for the icon fill (sets --hmf-icon-color) */
 	fill?: string;
 	/** Additional CSS class names */
 	className?: string;
 	/** Test ID for testing */
 	testId?: string;
 	/** Any additional props to pass to the SVG element */
 	[key: string]: any;
 }

 /**
  * HomefieldIcon - Dynamic icon component that mirrors Angular's homefield-icon
  *
  * This component provides a unified way to render icons by name with automatic
  * size variant resolution. It requires icons to be registered before use.
  *
  * @example
  * ```tsx
  * // 1. Register icons in your app's entry point (e.g., App.tsx or index.tsx):
  * import {
  *   registerIcons,
  *   HomefieldIconAlertHelpFilled,
  *   HomefieldIconAlertHelpFilled32
  * } from '@dsg-tech/homefield-react-icons';
  *
  * registerIcons([
  *   ['alert-help-filled', HomefieldIconAlertHelpFilled, { 32: HomefieldIconAlertHelpFilled32 }]
  * ]);
  *
  * // 2. Use the component anywhere in your app:
  * import { HomefieldIcon } from '@dsg-tech/homefield-react-icons';
  *
  * // Basic usage (24px default)
  * <HomefieldIcon name="alert-help-filled" />
  *
  * // With size alias
  * <HomefieldIcon name="alert-help-filled" size="lg" />
  *
  * // With numeric size (uses sized variant if available)
  * <HomefieldIcon name="alert-help-filled" size={32} />
  *
  * // With fill color
  * <HomefieldIcon name="alert-help-filled" fill="var(--hmf-primary500)" />
  *
  * // With additional props
  * <HomefieldIcon
  *   name="alert-help-filled"
  *   className="my-icon"
  *   testId="help-icon"
  *   aria-label="Help"
  * />
  * ```
  */
 export const HomefieldIcon: React.FC<HomefieldIconProps> = ({
 	name,
 	size = 'md',
 	fill,
 	className,
 	testId,
 	...restProps
 }) => {
 	// Convert size alias to numeric value
 	const numericSize =
 		typeof size === 'number'
 			? size
 			: ICON_SIZE_ALIASES[size as keyof typeof ICON_SIZE_ALIASES] ?? ICON_SIZE_ALIASES.md;

 	// Get the appropriate icon component from registry
 	const ResolvedIcon: IconComponent | undefined = iconRegistry.getIconBySize(name, numericSize);

 	// Handle unregistered icons
 	if (!ResolvedIcon) {
 		if (process.env['NODE_ENV'] === 'development') {
 			console.warn(
 				`HomefieldIcon: Icon "${name}" not found in registry. ` +
 					`Did you register it with registerIcons()?`
 			);
 		}
 		return null;
 	}

 	// Build style object with fill override if provided
 	const style: CSSProperties = fill ? ({ '--hmf-icon-color': fill } as CSSProperties) : {};

 	// Merge any existing style from restProps
 	const existingStyle = restProps['style'] as CSSProperties | undefined;
 	const mergedStyle = existingStyle ? { ...style, ...existingStyle } : style;

 	return (
 		<ResolvedIcon
 			width={numericSize}
 			height={numericSize}
 			className={className}
 			data-testid={testId}
 			{...restProps}
 			style={Object.keys(mergedStyle).length > 0 ? mergedStyle : undefined}
 		/>
 	);
 };

 // Re-export registry utilities for convenience
 export { iconRegistry, registerIcons };
 export type { IconComponent, IconRegistration };

