 #!/usr/bin/env node

 /**
  * @format
  *
  * Single-pass React Native icon generation script.
  *
  * Reads source SVGs, runs them through SVGR with SVGO optimization,
  * and writes final components with the shared IconProps interface.
  * No post-processing step needed.
  *
  * Usage: node tools/scripts/generate-rn-icons.js
  */

 const fs = require('fs');
 const path = require('path');
 const { transform } = require('@svgr/core');
 const { singleColorConfig, multiColorConfig } = require('../svg-conversion-configs/svgr.react-native.config');

 const ICONS_SRC = path.resolve(__dirname, '../../libs/icons');
 const ICON_LIB = path.resolve(
 	__dirname,
 	'../../libs/output/hmf-react-native-icons/src/lib/components/icon-library'
 );
 const ASSETS_DIR = path.join(ICON_LIB, 'assets');
 const MULTI_DIR = path.join(ICON_LIB, 'assets-multi');

 const VALID_SIZES = [12, 16, 20, 24, 32, 40, 48];

 // ---------------------------------------------------------------------------
 // Helpers
 // ---------------------------------------------------------------------------

 function kebabToPascal(str) {
 	return str
 		.split('-')
 		.map((part) => part.charAt(0).toUpperCase() + part.slice(1))
 		.join('');
 }

 function ensureDir(dir) {
 	if (!fs.existsSync(dir)) {
 		fs.mkdirSync(dir, { recursive: true });
 	}
 }

 function cleanDir(dir) {
 	if (!fs.existsSync(dir)) return;
 	for (const file of fs.readdirSync(dir)) {
 		const full = path.join(dir, file);
 		if (fs.statSync(full).isFile()) {
 			fs.unlinkSync(full);
 		}
 	}
 }

 function collectSvgFiles(baseDir) {
 	const entries = fs.readdirSync(baseDir, { withFileTypes: true });
 	const files = [];

 	for (const entry of entries) {
 		const fullPath = path.join(baseDir, entry.name);
 		if (entry.isFile() && entry.name.endsWith('.svg')) {
 			files.push(fullPath);
 		} else if (entry.isDirectory()) {
 			// Size variant directories (e.g., alert-help-filled/)
 			const subFiles = fs.readdirSync(fullPath).filter((f) => f.endsWith('.svg'));
 			for (const sub of subFiles) {
 				files.push(path.join(fullPath, sub));
 			}
 		}
 	}

 	return files;
 }

 /**
  * Parse an SVG filename into base name and optional size.
  * e.g. "alert-help-filled-12.svg" -> { baseName: "alert-help-filled", size: 12 }
  *      "alert-help-filled.svg"    -> { baseName: "alert-help-filled", size: null }
  */
 function parseSvgFilename(filePath) {
 	const name = path.basename(filePath, '.svg');
 	const sizeMatch = name.match(/^(.+)-(\d+)$/);

 	if (sizeMatch) {
 		const size = parseInt(sizeMatch[2], 10);
 		if (VALID_SIZES.includes(size)) {
 			return { baseName: sizeMatch[1], size };
 		}
 	}

 	return { baseName: name, size: null };
 }

 // ---------------------------------------------------------------------------
 // SVGR transform
 // ---------------------------------------------------------------------------

 async function transformSvg(svgCode, componentName, config) {
 	const code = await transform(svgCode, {
 		native: true,
 		typescript: true,
 		plugins: ['@svgr/plugin-svgo', '@svgr/plugin-jsx'],
 		svgoConfig: config.svgoConfig,
 		template: config.template,
 		prettier: false,
 	}, {
 		componentName: `Svg${componentName}`,
 	});

 	return code;
 }

 // ---------------------------------------------------------------------------
 // Main generation
 // ---------------------------------------------------------------------------

 async function generateIcons(srcDir, outDir, svgrConfig) {
 	const svgFiles = collectSvgFiles(srcDir);
 	const generated = [];
 	const seenNames = new Set();
 	for (const svgPath of svgFiles) {
 		const svgCode = fs.readFileSync(svgPath, 'utf8');
 		const { baseName, size } = parseSvgFilename(svgPath);

 		const pascalBase = kebabToPascal(baseName);
 		const componentName = size ? `${pascalBase}${size}` : pascalBase;
 		const nameLower = componentName.toLowerCase();
 		const outFile = path.join(outDir, `${componentName}.tsx`);

 		if (seenNames.has(nameLower) || fs.existsSync(outFile)) {
 			console.warn(`  SKIP: ${path.basename(svgPath)} — ${componentName} collides with existing component`);
 			continue;
 		}
 		seenNames.add(nameLower);

 		const code = await transformSvg(svgCode, componentName, svgrConfig);

 		fs.writeFileSync(outFile, code);
 		generated.push({ componentName, baseName: pascalBase, size });
 	}

 	return generated;
 }

 function writeIndex(outDir, entries, multiEntries) {
 	const lines = [];

 	// Single-color
 	for (const { componentName } of entries) {
 		lines.push(`export { default as ${componentName} } from './${componentName}';`);
 	}

 	// Multi-color (from sibling directory)
 	if (multiEntries) {
 		for (const { componentName } of multiEntries) {
 			lines.push(`export { default as ${componentName} } from '../assets-multi/${componentName}';`);
 		}
 	}

 	lines.sort();
 	fs.writeFileSync(path.join(outDir, 'index.ts'), lines.join('\n') + '\n');
 }

 async function main() {
 	console.log('Generating React Native icons...');

 	// Clean output dirs
 	ensureDir(ASSETS_DIR);
 	ensureDir(MULTI_DIR);
 	cleanDir(ASSETS_DIR);
 	cleanDir(MULTI_DIR);

 	// Generate single-color icons
 	const singleEntries = await generateIcons(
 		path.join(ICONS_SRC, 'single-color'),
 		ASSETS_DIR,
 		singleColorConfig
 	);
 	console.log(`  Single-color: ${singleEntries.length} components`);

 	// Generate multi-color icons
 	const multiEntries = await generateIcons(
 		path.join(ICONS_SRC, 'multi-color'),
 		MULTI_DIR,
 		multiColorConfig
 	);
 	console.log(`  Multi-color: ${multiEntries.length} components`);

 	// Write index files
 	writeIndex(ASSETS_DIR, singleEntries, multiEntries);
 	writeIndex(MULTI_DIR, multiEntries, null);

 	// Summary
 	const withVariants = new Set(
 		singleEntries.filter((e) => e.size !== null).map((e) => e.baseName)
 	);
 	console.log(`  Size variants: ${withVariants.size} icons have per-size SVGs`);
 	console.log(`  Total: ${singleEntries.length + multiEntries.length} components`);
 	console.log('Done.');
 }

 main().catch((err) => {
 	console.error('Error generating icons:', err);
 	process.exit(1);
 });

