 import React, { useMemo, useState } from 'react';
 import { View, Text, TextInput, SectionList, StyleSheet, SectionListData } from 'react-native';
 import { Meta, StoryObj } from '@storybook/react';
 import * as AllIcons from './assets';
 import * as MultiColorIcons from './assets-multi';

 type IconEntry = {
 	name: string;
 	displayName: string;
 	multiColor: boolean;
 	Component: React.ComponentType<{ width?: number; height?: number; color?: string }>;
 };

 type IconRow = IconEntry[];
 type RowSection = SectionListData<IconRow, { title: string; count: number }>;

 function pascalToKebab(name: string): string {
 	return name
 		.replace(/([a-z0-9])([A-Z])/g, '$1-$2')
 		.replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
 		.toLowerCase();
 }

 function getCategory(kebabName: string): string {
 	const first = kebabName.split('-')[0];
 	return first.charAt(0).toUpperCase() + first.slice(1);
 }

 const multiColorNames = new Set(Object.keys(MultiColorIcons));

 const allIcons: IconEntry[] = Object.entries(AllIcons)
 	.filter(([name]) => !/\d+$/.test(name))
 	.map(([name, Component]) => ({
 		name,
 		displayName: pascalToKebab(name),
 		multiColor: multiColorNames.has(name),
 		Component: Component as IconEntry['Component']
 	}))
 	.sort((a, b) => a.displayName.localeCompare(b.displayName));

 const COLUMN_COUNT = 4;

 function chunk(arr: IconEntry[], size: number): IconRow[] {
 	const rows: IconRow[] = [];
 	for (let i = 0; i < arr.length; i += size) {
 		rows.push(arr.slice(i, i + size));
 	}
 	return rows;
 }

 function buildSections(icons: IconEntry[]): { sections: RowSection[]; total: number } {
 	const grouped = new Map<string, IconEntry[]>();
 	for (const icon of icons) {
 		const category = getCategory(icon.displayName);
 		const list = grouped.get(category);
 		if (list) {
 			list.push(icon);
 		} else {
 			grouped.set(category, [icon]);
 		}
 	}

 	const sections = Array.from(grouped.entries())
 		.sort(([a], [b]) => a.localeCompare(b))
 		.map(([title, items]) => ({
 			title,
 			count: items.length,
 			data: chunk(items, COLUMN_COUNT)
 		}));

 	return { sections, total: icons.length };
 }

 const IconGallery = () => {
 	const [search, setSearch] = useState('');

 	const { sections, matchCount } = useMemo(() => {
 		const query = search.toLowerCase().trim();
