 	it('returns null for an unregistered icon', () => {
 		expect(render(<HmfIcon name="nonexistent" />).toJSON()).toBeNull();
 	});

 	it('warns when rendering an unregistered icon', () => {
 		render(<HmfIcon name="nonexistent" />);
 		expect(console.warn).toHaveBeenCalledWith('HmfIcon: "nonexistent" is not registered.');
 	});

 	it('selects the 32px variant when size resolves to 32', () => {
 		const props = rootProps(
 			render(
 				<HmfIcon
 					name="alert-help-filled"
 					size="lg"
 				/>
 			).toJSON()
 		);
 		expect(props.width).toBe(32);
 		expect(props.height).toBe(32);
 	});

 	it('keeps requested dimensions when no exact size variant exists', () => {
 		const props = rootProps(
 			render(
 				<HmfIcon
 					name="alert-help-filled"
 					size={64}
 				/>
 			).toJSON()
 		);
 		expect(props.width).toBe(64);
 		expect(props.height).toBe(64);
 	});
 });

