1. /** @format */
2. 
3. import React from 'react';
4. import type { SvgProps } from 'react-native-svg';
5. import { iconRegistry } from './IconRegistry';
6. import { ICON_SIZE_ALIASES } from './icon-size-aliases';
7. 
8. type SizeAlias = keyof typeof ICON_SIZE_ALIASES;
9. 
10. interface HmfIconProps extends Omit<SvgProps, 'width' | 'height'> {
11. 	/** Icon name in kebab-case (e.g., 'alert-help-filled') */
12. 	name: string;
13. 	/** Size alias (e.g., 'md', 'lg') or specific pixel value (e.g., 32) */
14. 	size?: SizeAlias | number;
15. 	/** Test ID for testing */
16. 	testID?: string;
17. }
18. 
19. /**
20.  * HmfIcon - Dynamic icon component for React Native
21.  *
22.  * Renders icons by name with automatic size variant resolution.
23.  * Icons must be registered before use via `registerIcons()`.
24.  *
25.  * @example
26.  * ```tsx
27.  * import { HmfIcon, registerIcons, AlertHelpFilled } from '@dsg-tech/hmf-react-native-icons';
28.  *
29.  * registerIcons([['alert-help-filled', AlertHelpFilled]]);
30.  *
31.  * <HmfIcon name="alert-help-filled" size="md" color="#000" />
32.  * <HmfIcon name="alert-help-filled" size={32} />
33.  * ```
34.  */
35. export const HmfIcon: React.FC<HmfIconProps> = ({ name, size = 'md', testID, ...props }) => {
36. 	const numericSize = typeof size === 'string' ? ICON_SIZE_ALIASES[size] : size;
37. 	const IconComponent = iconRegistry.getIconBySize(name, numericSize);
38. 
39. 	if (!IconComponent) {
