 /** @format */

 import React from 'react';
 import type { SvgProps } from 'react-native-svg';
 import { iconRegistry } from './IconRegistry';
 import { ICON_SIZE_ALIASES } from './icon-size-aliases';

 type SizeAlias = keyof typeof ICON_SIZE_ALIASES;

 interface HmfIconProps extends Omit<SvgProps, 'width' | 'height'> {
 	/** Icon name in kebab-case (e.g., 'alert-help-filled') */
 	name: string;
 	/** Size alias (e.g., 'md', 'lg') or specific pixel value (e.g., 32) */
 	size?: SizeAlias | number;
 	/** Test ID for testing */
 	testID?: string;
 }

 /**
  * HmfIcon - Dynamic icon component for React Native
  *
  * Renders icons by name with automatic size variant resolution.
  * Icons must be registered before use via `registerIcons()`.
  *
  * @example
  * ```tsx
  * import { HmfIcon, registerIcons, AlertHelpFilled } from '@dsg-tech/hmf-react-native-icons';
  *
  * registerIcons([['alert-help-filled', AlertHelpFilled]]);
  *
  * <HmfIcon name="alert-help-filled" size="md" color="#000" />
  * <HmfIcon name="alert-help-filled" size={32} />
  * ```
  */
 export const HmfIcon: React.FC<HmfIconProps> = ({ name, size = 'md', testID, ...props }) => {
 	const numericSize = typeof size === 'string' ? ICON_SIZE_ALIASES[size] : size;
 	const IconComponent = iconRegistry.getIconBySize(name, numericSize);

 	if (!IconComponent) {
 		if (__DEV__) {
 			console.warn(`HmfIcon: "${name}" is not registered.`);
 		}
 		return null;
 	}

 	return (
 		<IconComponent
 			width={numericSize}
 			height={numericSize}
 			testID={testID}
 			{...props}
 		/>
 	);
 };

