 import type { ComponentType } from 'react';
 import type { SvgProps } from 'react-native-svg';
 import * as iconAssets from './assets';
 import { iconRegistry, registerIcons } from './IconRegistry';
 import type { IconRegistration } from './IconRegistry';

 type IconComponent = ComponentType<SvgProps>;
 type RegistrationDraft = {
 	base?: IconComponent;
 	sizes: Partial<Record<number, IconComponent>>;
 };

 const VALID_ICON_SIZES = new Set([12, 16, 20, 24, 32, 40, 48]);

 function pascalToKebab(name: string): string {
 	return name
 		.replace(/([a-z0-9])([A-Z])/g, '$1-$2')
 		.replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
 		.toLowerCase();
 }

 function parseComponentName(componentName: string): { baseComponentName: string; size?: number } {
 	const sizeMatch = componentName.match(/^(.*?)(\d+)$/);

 	if (!sizeMatch) {
 		return { baseComponentName: componentName };
 	}

 	const parsedSize = Number.parseInt(sizeMatch[2], 10);
 	if (!VALID_ICON_SIZES.has(parsedSize)) {
 		return { baseComponentName: componentName };
 	}

 	return {
 		baseComponentName: sizeMatch[1],
 		size: parsedSize
 	};
 }

 function buildRegistrations(icons: Record<string, unknown>): IconRegistration<IconComponent>[] {
 	const registrations = new Map<string, RegistrationDraft>();

 	for (const [componentName, component] of Object.entries(icons)) {
 		if (typeof component !== 'function') {
 			continue;
 		}

 		const { baseComponentName, size } = parseComponentName(componentName);
 		const iconName = pascalToKebab(baseComponentName);
 		const draft = registrations.get(iconName) ?? { sizes: {} };
 		const typedComponent = component as IconComponent;

 		if (size === undefined) {
 			draft.base = typedComponent;
 		} else {
 			draft.sizes[size] = typedComponent;
 		}

 		registrations.set(iconName, draft);
 	}

 	return Array.from(registrations.entries())
 		.map(([iconName, draft]) => {
 			const fallbackBase =
 				draft.base ??
 				draft.sizes[24] ??
 				Object.values(draft.sizes).find((component) => component !== undefined);

 			if (!fallbackBase) {
 				return null;
 			}

 			const hasSizes = Object.keys(draft.sizes).length > 0;
 			if (!hasSizes) {
 				return [iconName, fallbackBase] satisfies IconRegistration<IconComponent>;
 			}

 			return [iconName, fallbackBase, draft.sizes] satisfies IconRegistration<IconComponent>;
 		})
 		.filter((registration): registration is IconRegistration<IconComponent> => registration !== null)
 		.sort((left, right) => left[0].localeCompare(right[0]));
 }

 const AUTO_REGISTRATIONS = buildRegistrations(iconAssets);

 export const ALL_ICON_NAMES = Object.freeze(AUTO_REGISTRATIONS.map(([name]) => name));
 export type HomefieldIconName = (typeof ALL_ICON_NAMES)[number];

 export const registerAllIcons = (): void => {
 	registerIcons(AUTO_REGISTRATIONS);
 };

 let hasAutoRegistered = false;

 export const ensureIconsRegistered = (): void => {
 	if (hasAutoRegistered && iconRegistry.getRegisteredNames().length > 0) {
 		return;
 	}

 	registerAllIcons();
 	hasAutoRegistered = true;
 };

 export const __resetAutoRegistrationForTests = (): void => {
 	hasAutoRegistered = false;
 };

