 import { Meta, Canvas } from '@storybook/addon-docs/blocks';

 <Meta title="Development/React Native Icons/Use" />

 # How To Use A Homefield Icon

 Homefield React Native icons can be used either as direct component imports or with the dynamic `HmfIcon` renderer.

 ## Direct component import

 ```typescript
 import { AlertAnnouncement } from '@dsg-tech/homefield-react-native-icons';
 ```

 ### Basic example

 ```tsx
 import React from 'react';
 import { AlertAnnouncement } from '@dsg-tech/homefield-react-native-icons';

 const App = () => {
 	return <AlertAnnouncement />;
 };
 ```

 ### Override props example

 ```tsx
 import React from 'react';
 import { AlertAnnouncement } from '@dsg-tech/homefield-react-native-icons';

 const App = () => {
 	// You can use any valid SVG element prop as an override
 	return (
 		<AlertAnnouncement
 			width={50}
 			height={50}
 			fill="#ffffff"
 		/>
 	);
 };
 ```

 ## Dynamic usage with `HmfIcon`

 Use one of these registration options before rendering `HmfIcon`:

 - `registerAllIcons()` for convenience (registers all icons)
 - `registerIcons([...])` for tree-shaken bundles (register only what your app uses)

 ```tsx
 import React from 'react';
 import { HmfIcon, registerAllIcons } from '@dsg-tech/homefield-react-native-icons';

 const App = () => {
 	registerAllIcons();

 	return (
 		<HmfIcon
 			name="alert-help-filled"
 			size="lg"
 			color="#000000"
 		/>
 	);
 };
 ```

